import subprocess
import tempfile
import os
import resource
from pathlib import Path

def execute_python(code: str, timeout: int = 10) -> dict:
    """Run Python code in a subprocess and return stdout/stderr."""
    with tempfile.NamedTemporaryFile(suffix=".py", mode="w", delete=False) as f:
        f.write(code)
        script_path = f.name

    try:
        result = subprocess.run(
            ["python3", script_path],
            capture_output=True,
            text=True,
            timeout=timeout,
            # Limit memory to 256 MB on Linux
            preexec_fn=lambda: resource.setrlimit(
                resource.RLIMIT_AS, (256 * 1024 * 1024, 256 * 1024 * 1024)
            ) if os.name != "nt" else None,
        )
        return {
            "stdout": result.stdout[:8192],   # cap output size
            "stderr": result.stderr[:2048],
            "returncode": result.returncode,
            "error": None,
        }
    except subprocess.TimeoutExpired:
        return {"stdout": "", "stderr": "", "returncode": -1, "error": f"Timed out after {timeout}s"}
    except Exception as e:
        return {"stdout": "", "stderr": "", "returncode": -1, "error": str(e)}
    finally:
        os.unlink(script_path)

import anthropic
import json

client = anthropic.Anthropic()

tools = [
    {
        "name": "execute_python",
        "description": (
            "Execute Python 3 code and return stdout, stderr, and return code. "
            "Use for calculations, data processing, file operations, or any task "
            "that benefits from running actual code. Timeout is 10 seconds."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "code": {
                    "type": "string",
                    "description": "Python 3 code to execute"
                },
                "timeout": {
                    "type": "integer",
                    "description": "Timeout in seconds (default 10, max 30)",
                    "default": 10
                }
            },
            "required": ["code"]
        }
    }
]

def run_agent(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=4096,
            tools=tools,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            # Extract final text response
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use" and block.name == "execute_python":
                    timeout = min(block.input.get("timeout", 10), 30)
                    result = execute_python(block.input["code"], timeout=timeout)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": json.dumps(result),
                    })

            messages.append({"role": "assistant", "content": response.content})
            messages.append({"role": "user", "content": tool_results})

from jupyter_client import KernelManager

class PythonKernel:
    def __init__(self):
        self.km = KernelManager(kernel_name="python3")
        self.km.start_kernel()
        self.kc = self.km.client()
        self.kc.start_channels()
        self.kc.wait_for_ready(timeout=30)

    def execute(self, code: str, timeout: int = 30) -> dict:
        msg_id = self.kc.execute(code)
        stdout_parts, stderr_parts = [], []

        while True:
            try:
                msg = self.kc.get_iopub_msg(timeout=timeout)
            except Exception:
                return {"stdout": "", "stderr": "", "error": "Timeout waiting for kernel"}

            msg_type = msg["msg_type"]
            content = msg["content"]

            if msg_type == "stream":
                if content["name"] == "stdout":
                    stdout_parts.append(content["text"])
                else:
                    stderr_parts.append(content["text"])
            elif msg_type == "error":
                return {
                    "stdout": "".join(stdout_parts),
                    "stderr": "".join(stderr_parts),
                    "error": "\n".join(content["traceback"]),
                }
            elif msg_type == "status" and content["execution_state"] == "idle":
                break

        return {
            "stdout": "".join(stdout_parts)[:8192],
            "stderr": "".join(stderr_parts)[:2048],
            "error": None,
        }

    def shutdown(self):
        self.kc.stop_channels()
        self.km.shutdown_kernel()
